@import 'variables'

@mixin between($from, $to)
  @media (min-width: $from) and (max-width: $to)
    @content

@mixin max-width($width)
  @media (max-width: $width)
    @content

@mixin min-width($width)
  @media (min-width: $width)
    @content

// min-width: $screen-xs
@mixin min-width-xxs
  @content

@mixin max-width-xxs
  @media (max-width: $screen-xs-min)
    @content

@mixin min-width-xs
  @media (min-width: $screen-xs-min)
    @content

// max-width: $screen-xs
@mixin max-width-xs
  @media (max-width: $screen-xs-max)
    @content

// min-width: $screen-sm
@mixin min-width-sm
  @media (min-width: $screen-sm-min)
    @content

// max-width: $screen-sm
@mixin max-width-sm
  @media (max-width: $screen-sm-max)
    @content

// min-width: $screen-md
@mixin min-width-md
  @media (min-width: $screen-md-min)
    @content

// max-width: $screen-md
@mixin max-width-md
  @media (max-width: $screen-md-max)
    @content

// min-width: $screen-lg
@mixin min-width-lg
  @media (min-width: $screen-lg-min)
    @content

// hide element in specific viewport range
@mixin hide-xs
  @media (max-width: $screen-xs-max)
    display: none

@mixin hide-sm
  @media (min-width: $screen-sm-min) and (max-width: $screen-sm-max)
    display: none

@mixin hide-md
  @media (min-width: $screen-md-min) and (max-width: $screen-md-max)
    display: none

@mixin hide-lg
  @media (min-width: $screen-lg-min)
    display: none

=structure-float($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $grouped-styles: false)
  @if $dir == ltr or $dir == both
    @if $location > 1 and $location < column-count($columns)
      @if $grouped-styles == false
        margin-right: -100%
        float: left
      margin-left: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      @if $grouped-styles == false
        margin-right: -100%
        float: left
      margin-left: 0
    @if $location == column-count($columns)
      float: right
      margin-right: 0
  @if $dir == rtl
    @if $location > 1 and $location < column-count($columns)
      @if $grouped-styles == false
        margin-left: -100%
        float: right
      margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      @if $grouped-styles == false
        margin-left: -100%
        float: right
      margin-right: 0
    @if $location == column-count($columns)
      float: left
      margin-left: 0
  @if $dir == both
    #{$rtl-selector} &
      @if $location > 1 and $location < column-count($columns)
        @if $grouped-styles == false
          margin-left: -100%
          float: right
        margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
      @if $location == 1
        @if $grouped-styles == false
          margin-left: -100%
          float: right
        margin-right: 0
      @if $location == column-count($columns)
        float: left
        margin-left: 0
